import React from 'react';
import PropTypes from 'prop-types';
import { IoMdSunny } from 'react-icons/io';
import { IoMdPartlySunny } from 'react-icons/io';
import { IoMdCloudy } from 'react-icons/io';
import { IoMdThunderstorm } from 'react-icons/io';
import { IoMdRainy } from 'react-icons/io';
import { IoMdSnow } from 'react-icons/io';
import {
    CLOUD,
    CLOUDY,
    SUN,
    RAIN,
    SNOW,
    STORM,
} from './../../../constants/weathers';

const icons = {
    [CLOUD]: 'cloud',
    [CLOUDY]: 'cloudy',
    [SUN]: 'sun',
    [RAIN]: 'rain',
    [SNOW]: 'snow',
    [STORM]: 'storm',

};
const getWeatherIcon = weatherState => {
    const icon = icons[weatherState];

    if(icon === 'snow')
        return <IoMdSnow size='40px'/>       
    
    else if (icon === 'cloud')
        return  <IoMdCloudy size='40px'/>
         
    else if (icon === 'cloudy')
        return <IoMdPartlySunny size='40px'/>
    
    else if(icon === 'storm')
        return <IoMdThunderstorm size='40px'/>
    
    else if(icon === 'rain')
        return <IoMdRainy size='40px'/>
    
    else   
        return <IoMdSunny size='40px'/>
};


const WeatherTemperature = ({ temperature, weatherState}) => (
    <div>
        {
            getWeatherIcon(weatherState)
        }
        <span>
            { `${temperature} C°`}
        </span>
    </div>
);

WeatherTemperature.propTypes = {
    temperature: PropTypes.number.isRequired,
    weatherState: PropTypes.string.isRequired,
};

export default WeatherTemperature;
